      pushToast({ title: 'Thất bại', message: 'Lá»—i táº£i lá»‹ch sá»­ dá»± Ä‘oÃ¡n', type: 'error' });
      console.error(err);
    } finally {
      setPredictionsLoading(false);
    }
  };

  // Model Functions
  const fetchModelStatus = async () => {
    try {
      setModelLoading(true);
      const response = await adminService.getModelStatus();
      setModelStatus(response.data.data);
    } catch (err) {
      pushToast({ title: 'Thất bại', message: 'Lá»—i táº£i tráº¡ng thÃ¡i model', type: 'error' });
      console.error(err);
    } finally {
      setModelLoading(false);
    }
  };

  const handleUpdateModel = async () => {
    if (window.confirm('Báº¡n cÃ³ cháº¯c cháº¯n muá»‘n cáº­p nháº­t model? QuÃ¡ trÃ¬nh nÃ y cÃ³ thá»ƒ máº¥t vÃ i phÃºt.')) {
