            </table>
          </div>
        </div>
      )}

      {/* Predictions Tab */}
      {activeTab === 'predictions' && (
        <div className="tab-content">
          <div className="section-header">
            <h2>ðŸ”® Lá»‹ch sá»­ dá»± Ä‘oÃ¡n bá»‡nh</h2>
            <button className="btn-primary" onClick={fetchPredictions}>
              ðŸ”„ LÃ m má»›i
