            <h2>âš™ï¸ Tráº¡ng thÃ¡i vÃ  quáº£n lÃ½ Model</h2>
            <button
              className="btn-primary"
              onClick={handleUpdateModel}
              disabled={updatingModel}
            >
              {updatingModel ? 'â³ Äang cáº­p nháº­t...' : 'ðŸš€ Cáº­p nháº­t Model'}
            </button>
          </div>

          {modelLoading ? (
            <div className="flex-center admin-ai__loading-container--model">
              <div className="spinner"></div>
            </div>
          ) : modelStatus ? (
            <div className="model-status-grid">
              <div className="status-card">
                <h3>ðŸ“¦ PhiÃªn báº£n Model</h3>
                <p className="status-value">{modelStatus.version || 'N/A'}</p>
              </div>

              <div className="status-card">
                <h3>ðŸŽ¯ Äá»™ chÃ­nh xÃ¡c</h3>
